import { useState } from "react";
import MovieList from "./components/MovieList";
function App() {
  const [movies, setMovies] = userState([
    { id: 1, title: "Inception" },
    { id: 2, title: "Interstellar" }
  ]);
  return (
    <div>
      <h1> My Movies App </h1>
      <MovieList movies={movies} />
    </div>
  );

}

export default App;
